import React, { useState, useRef } from 'react';
import { LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Search, Heart, TrendingUp, AlertCircle, Menu, X, Download, Share2, Settings, LogOut, PieChart as PieChartIcon } from 'lucide-react';

const App = () => {
  const [page, setPage] = useState('landing');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [scanInput, setScanInput] = useState('');
  const [scanResults, setScanResults] = useState([]);
  const [selectedStock, setSelectedStock] = useState(null);
  const [loading, setLoading] = useState(false);
  const [watchlist, setWatchlist] = useState([]);
  const [alerts, setAlerts] = useState([]);
  const [alertPrice, setAlertPrice] = useState('');
  const [activeTab, setActiveTab] = useState('screener');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [subscriptionTier, setSubscriptionTier] = useState('free');
  const [mobileView, setMobileView] = useState(window.innerWidth < 768);
  const [chartData, setChartData] = useState([]);
  const [lines, setLines] = useState([]);
  const [isDrawing, setIsDrawing] = useState(false);
  const [drawMode, setDrawMode] = useState(null);
  const canvasRef = useRef(null);
  const [startPoint, setStartPoint] = useState(null);
  const [filterType, setFilterType] = useState('all');
  const [adminStats, setAdminStats] = useState({ users: 1250, revenue: '$45,320', subs: 380 });

  React.useEffect(() => {
    const handleResize = () => setMobileView(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const generateStockData = (ticker) => ({
    ticker: ticker.toUpperCase(),
    company: `${ticker} Corp`,
    price: (Math.random() * 200 + 20).toFixed(2),
    change: ((Math.random() - 0.5) * 30).toFixed(2),
    percentChange: ((Math.random() - 0.5) * 15).toFixed(2),
    volume: (Math.random() * 100000000).toFixed(0),
    avgVolume: (Math.random() * 80000000).toFixed(0),
    rsi: (Math.random() * 100).toFixed(1),
    rsi14: (Math.random() * 100).toFixed(1),
    macd: (Math.random() - 0.5).toFixed(3),
    macdSignal: (Math.random() - 0.5).toFixed(3),
    signal: (Math.random() * 100).toFixed(0),
    sma20: (Math.random() * 150 + 50).toFixed(2),
    sma50: (Math.random() * 150 + 50).toFixed(2),
    sma200: (Math.random() * 150 + 50).toFixed(2),
    ema12: (Math.random() * 150 + 50).toFixed(2),
    ema26: (Math.random() * 150 + 50).toFixed(2),
    bollingerUpper: (Math.random() * 200 + 120).toFixed(2),
    bollingerMiddle: (Math.random() * 150 + 80).toFixed(2),
    bollingerLower: (Math.random() * 100 + 50).toFixed(2),
    stochastic: (Math.random() * 100).toFixed(1),
    adx: (Math.random() * 50 + 20).toFixed(1),
    atr: (Math.random() * 10 + 1).toFixed(2),
    pe_ratio: (Math.random() * 40 + 5).toFixed(2),
    earnings_date: new Date(Date.now() + Math.random() * 90 * 24 * 60 * 60 * 1000).toLocaleDateString(),
    dayHigh: (Math.random() * 200 + 100).toFixed(2),
    dayLow: (Math.random() * 100 + 50).toFixed(2),
    fiftyTwoWeekHigh: (Math.random() * 300 + 150).toFixed(2),
    fiftyTwoWeekLow: (Math.random() * 100 + 30).toFixed(2),
    marketCap: `$${(Math.random() * 1000 + 50).toFixed(0)}B`,
    dividend: (Math.random() * 5).toFixed(2),
    earningsGap: Math.random() > 0.7,
    breakout: Math.random() > 0.5,
    oversold: (Math.random() * 100).toFixed(1) < 30,
    overbought: (Math.random() * 100).toFixed(1) > 70,
    volumeSpike: Math.random() > 0.6,
    priceTarget: (Math.random() * 200 + 30).toFixed(2),
    analyst: Math.floor(Math.random() * 30 + 5),
  });

  const generateChartData = () => {
    return Array.from({ length: 100 }, (_, i) => ({
      time: `${Math.floor(i / 4)}:${(i % 4) * 15}`,
      price: Math.random() * 50 + 100,
      volume: Math.random() * 1000000,
      sma20: Math.random() * 50 + 90,
      sma50: Math.random() * 50 + 95,
    }));
  };

  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const url = isSignUp ? 'http://localhost:5001/api/auth/register' : 'http://localhost:5001/api/auth/login';
      const res = await fetch(url, { 
        method: 'POST', 
        headers: { 'Content-Type': 'application/json' }, 
        body: JSON.stringify(isSignUp ? { email, password, name } : { email, password }) 
      });
      const data = await res.json();
      if (data.token) {
        localStorage.setItem('token', data.token);
        setIsLoggedIn(true);
        setPage('app');
        setEmail('');
        setPassword('');
        setName('');
      } else {
        alert('Error: ' + (data.error || 'Failed'));
      }
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  const handleAdminLogin = () => {
    if (email === 'admin@baileysgauge.com' && password === 'admin123') {
      setIsAdmin(true);
      setIsLoggedIn(true);
      setPage('app');
      setEmail('');
      setPassword('');
    } else {
      alert('Invalid admin credentials');
    }
  };

  const handleScan = async (e) => {
    e.preventDefault();
    if (!scanInput.trim()) return;
    setLoading(true);
    const tickers = scanInput.split(',').map(t => t.trim());
    const token = localStorage.getItem('token');
    try {
      const res = await fetch('http://localhost:5001/api/scan', { 
        method: 'POST', 
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + token }, 
        body: JSON.stringify({ tickers }) 
      });
      const data = await res.json();
      const enhanced = (data.results || []).map(r => ({ ...r, ...generateStockData(r.ticker) }));
      setScanResults(enhanced);
      setSelectedStock(null);
    } catch (err) {
      alert('Error: ' + err.message);
    }
    setLoading(false);
  };

  const toggleWatchlist = (ticker) => {
    if (watchlist.includes(ticker)) {
      setWatchlist(watchlist.filter(t => t !== ticker));
    } else {
      setWatchlist([...watchlist, ticker]);
    }
  };

  const addAlert = (ticker, price) => {
    if (!price) {
      alert('Enter a price');
      return;
    }
    setAlerts([...alerts, { id: Date.now(), ticker, price }]);
    setAlertPrice('');
  };

  const handleChartMouseDown = (e) => {
    if (!drawMode) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    setStartPoint({ x, y });
    setIsDrawing(true);
  };

  const handleChartMouseMove = (e) => {
    if (!isDrawing || !startPoint || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const currentX = e.clientX - rect.left;
    const currentY = e.clientY - rect.top;
    const ctx = canvas.getContext('2d');
    canvas.width = canvas.offsetWidth;
    canvas.height = canvas.offsetHeight;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    lines.forEach(line => {
      ctx.strokeStyle = line.color;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(line.x1, line.y1);
      ctx.lineTo(line.x2, line.y2);
      ctx.stroke();
    });
    ctx.strokeStyle = drawMode === 'trendline' ? '#00d9ff' : '#ff6b6b';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(startPoint.x, startPoint.y);
    ctx.lineTo(currentX, currentY);
    ctx.stroke();
  };

  const handleChartMouseUp = (e) => {
    if (!isDrawing || !startPoint || !canvasRef.current) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const endX = e.clientX - rect.left;
    const endY = e.clientY - rect.top;
    const newLine = { x1: startPoint.x, y1: startPoint.y, x2: endX, y2: endY, color: drawMode === 'trendline' ? '#00d9ff' : '#ff6b6b', type: drawMode };
    setLines([...lines, newLine]);
    setIsDrawing(false);
    setStartPoint(null);
  };

  const clearDrawing = () => {
    setLines([]);
    if (canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
    }
  };

  const downloadChart = () => {
    alert('Chart downloaded! (Stripe payment would be processed here)');
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setIsLoggedIn(false);
    setIsAdmin(false);
    setPage('landing');
  };

  // LANDING PAGE
  if (page === 'landing') {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0a0a14 0%, #1a1a2e 100%)', minHeight: '100vh', color: 'white', fontFamily: 'system-ui, -apple-system, sans-serif' }}>
        <nav style={{ background: 'rgba(10,10,20,0.9)', borderBottom: '1px solid rgba(0,217,255,0.1)', padding: '1rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h1 style={{ margin: 0, fontSize: mobileView ? '18px' : '26px', fontWeight: '800', color: '#00d9ff' }}>Bailey's Gauge</h1>
          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <button onClick={() => { setIsSignUp(false); setPage('auth'); }} style={{ padding: '0.75rem 1rem', background: 'transparent', color: '#00d9ff', border: '2px solid #00d9ff', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: mobileView ? '12px' : '14px' }}>Sign In</button>
            <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '0.75rem 1rem', background: '#00d9ff', color: '#0a0a14', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: mobileView ? '12px' : '14px' }}>Free Trial</button>
          </div>
        </nav>

        <div style={{ maxWidth: '1400px', margin: '0 auto', padding: mobileView ? '2rem 1rem' : '5rem 2rem' }}>
          <h2 style={{ fontSize: mobileView ? '36px' : '64px', fontWeight: '900', margin: '0 0 1rem', color: '#00d9ff', lineHeight: '1.1' }}>Professional Day Trading Command Center</h2>
          <p style={{ fontSize: mobileView ? '14px' : '18px', color: '#aaa', margin: '0 0 2rem', maxWidth: '600px' }}>Advanced technical analysis. Real-time alerts. Draw support/resistance. Find trades before they move. Professional-grade tools at half the price.</p>

          <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap', marginBottom: '3rem' }}>
            <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ padding: '1rem 2rem', background: '#00d9ff', color: '#0a0a14', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '16px' }}>Start Free Trial →</button>
            <button style={{ padding: '1rem 2rem', background: 'transparent', color: '#00d9ff', border: '2px solid #00d9ff', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '16px' }}>Watch Demo</button>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: mobileView ? '1fr' : 'repeat(3, 1fr)', gap: '2rem', marginBottom: '3rem' }}>
            {[
              { icon: '📊', title: '50+ Indicators', desc: 'RSI, MACD, Bollinger, Stochastic, ADX, ATR & more' },
              { icon: '⚡', title: 'Draw Tools', desc: 'Trendlines, support/resistance, annotations' },
              { icon: '🎯', title: 'Smart Alerts', desc: 'Price targets, earnings, breakouts, volume' },
              { icon: '📈', title: 'Advanced Charts', desc: 'Professional candlesticks, volume profiles' },
              { icon: '💼', title: 'Earnings Calendar', desc: 'Know when stocks report earnings' },
              { icon: '❤️', title: 'Watchlists', desc: 'Track 1000+ stocks, organize by strategy' },
              { icon: '📥', title: 'Export Data', desc: 'Download charts, analysis, trade lists' },
              { icon: '🔔', title: 'Real-Time Alerts', desc: 'Instant notifications on your phone' },
              { icon: '🏆', title: 'Win Rate Tracker', desc: 'Track your trades and performance' },
            ].map((f, i) => (
              <div key={i} style={{ background: 'rgba(0,217,255,0.05)', border: '1px solid rgba(0,217,255,0.2)', padding: '1.5rem', borderRadius: '12px' }}>
                <div style={{ fontSize: '32px', marginBottom: '0.5rem' }}>{f.icon}</div>
                <h3 style={{ margin: '0 0 0.5rem', fontSize: '16px', fontWeight: '700' }}>{f.title}</h3>
                <p style={{ margin: 0, color: '#aaa', fontSize: '13px' }}>{f.desc}</p>
              </div>
            ))}
          </div>

          <div style={{ background: 'rgba(0,217,255,0.05)', border: '1px solid rgba(0,217,255,0.2)', padding: mobileView ? '2rem 1rem' : '3rem 2rem', borderRadius: '12px', marginBottom: '3rem' }}>
            <h3 style={{ margin: '0 0 2rem', fontSize: '24px', fontWeight: '700', textAlign: 'center' }}>Simple Pricing</h3>
            <div style={{ display: 'grid', gridTemplateColumns: mobileView ? '1fr' : 'repeat(3, 1fr)', gap: '2rem' }}>
              {[
                { tier: 'Free', price: '$0', features: ['5 scans/day', 'Basic indicators', 'Watchlist (50 stocks)', 'Email support'] },
                { tier: 'Pro', price: '$29', features: ['Unlimited scans', 'All 50+ indicators', 'Advanced alerts', 'Draw tools', 'Email + chat support'], highlighted: true },
                { tier: 'Pro+', price: '$79', features: ['Everything in Pro', 'API access', 'Webhook alerts', 'Priority support', 'Custom indicators'] },
              ].map((plan, i) => (
                <div key={i} style={{ background: plan.highlighted ? 'rgba(0,217,255,0.15)' : 'transparent', border: plan.highlighted ? '2px solid #00d9ff' : '1px solid rgba(0,217,255,0.2)', padding: '2rem', borderRadius: '12px' }}>
                  <h4 style={{ margin: '0 0 0.5rem', fontSize: '18px', fontWeight: '700' }}>{plan.tier}</h4>
                  <p style={{ margin: '0 0 1.5rem', fontSize: '32px', fontWeight: '800', color: '#00d9ff' }}>{plan.price}<span style={{ fontSize: '14px', color: '#aaa' }}>/mo</span></p>
                  <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
                    {plan.features.map((f, j) => (
                      <li key={j} style={{ margin: '0.75rem 0', color: '#aaa', fontSize: '13px' }}>✓ {f}</li>
                    ))}
                  </ul>
                  <button onClick={() => { setIsSignUp(true); setPage('auth'); }} style={{ width: '100%', marginTop: '1.5rem', padding: '0.75rem', background: plan.highlighted ? '#00d9ff' : 'transparent', color: plan.highlighted ? '#0a0a14' : '#00d9ff', border: plan.highlighted ? 'none' : '1px solid #00d9ff', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '13px' }}>Get Started</button>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // AUTH PAGE
  if (page === 'auth') {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0a0a14 0%, #1a1a2e 100%)', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem', fontFamily: 'system-ui, -apple-system, sans-serif' }}>
        <div style={{ maxWidth: '450px', width: '100%', background: 'rgba(26,26,46,0.8)', padding: '3rem', borderRadius: '12px', border: '1px solid rgba(0,217,255,0.1)' }}>
          <h2 style={{ textAlign: 'center', color: 'white', marginTop: 0, marginBottom: '2rem', fontSize: '28px', fontWeight: '700' }}>{isSignUp ? 'Create Account' : 'Sign In'}</h2>

          {!isSignUp && (
            <div style={{ background: 'rgba(0,217,255,0.1)', border: '1px solid rgba(0,217,255,0.2)', padding: '1rem', borderRadius: '8px', marginBottom: '2rem', fontSize: '12px', color: '#aaa' }}>
              Demo admin: admin@baileysgauge.com / admin123
            </div>
          )}

          <form onSubmit={handleAuth}>
            {isSignUp && (
              <input type="text" placeholder="Full Name" value={name} onChange={(e) => setName(e.target.value)} style={{ width: '100%', padding: '0.875rem', marginBottom: '1rem', borderRadius: '8px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '14px', boxSizing: 'border-box' }} required />
            )}
            <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} style={{ width: '100%', padding: '0.875rem', marginBottom: '1rem', borderRadius: '8px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '14px', boxSizing: 'border-box' }} required />
            <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} style={{ width: '100%', padding: '0.875rem', marginBottom: '2rem', borderRadius: '8px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '14px', boxSizing: 'border-box' }} required />
            <button type="submit" disabled={loading} style={{ width: '100%', padding: '0.875rem', background: '#00d9ff', color: '#0a0a14', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '14px' }}>
              {loading ? 'Loading...' : (isSignUp ? 'Create Account' : 'Sign In')}
            </button>
          </form>

          {!isSignUp && (
            <>
              <div style={{ textAlign: 'center', margin: '2rem 0', color: '#666' }}>or</div>
              <button onClick={handleAdminLogin} style={{ width: '100%', padding: '0.875rem', background: 'rgba(0,217,255,0.1)', color: '#00d9ff', border: '1px solid rgba(0,217,255,0.2)', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '14px' }}>Admin Login</button>
            </>
          )}

          <p style={{ textAlign: 'center', color: '#aaa', marginTop: '1.5rem', fontSize: '14px' }}>
            {isSignUp ? 'Have an account? ' : "Don't have an account? "}
            <button onClick={() => setIsSignUp(!isSignUp)} style={{ background: 'none', border: 'none', color: '#00d9ff', cursor: 'pointer', fontWeight: '700' }}>{isSignUp ? 'Sign In' : 'Sign Up'}</button>
          </p>
          <button onClick={() => setPage('landing')} style={{ width: '100%', marginTop: '1rem', padding: '0.75rem', background: 'transparent', color: '#aaa', border: '1px solid rgba(0,217,255,0.2)', borderRadius: '8px', cursor: 'pointer' }}>← Back</button>
        </div>
      </div>
    );
  }

  // MAIN APP
  if (page === 'app' && isLoggedIn) {
    return (
      <div style={{ background: 'linear-gradient(135deg, #0a0a14 0%, #1a1a2e 100%)', minHeight: '100vh', color: 'white', display: 'flex', fontFamily: 'system-ui, -apple-system, sans-serif' }}>
        {/* SIDEBAR */}
        {sidebarOpen && (
          <div style={{ width: mobileView ? '100%' : '280px', background: 'rgba(26,26,46,0.8)', borderRight: '1px solid rgba(0,217,255,0.1)', padding: '1.5rem', overflowY: 'auto', maxHeight: '100vh', position: mobileView ? 'fixed' : 'relative', zIndex: 100 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
              <h2 style={{ margin: 0, fontSize: '18px', fontWeight: '800' }}>Bailey's Gauge</h2>
              {mobileView && <button onClick={() => setSidebarOpen(false)} style={{ background: 'none', border: 'none', color: '#00d9ff', cursor: 'pointer', fontSize: '20px' }}>✕</button>}
            </div>

            {isAdmin && (
              <>
                <p style={{ margin: '0 0 1rem', fontSize: '11px', color: '#00d9ff', fontWeight: '700', textTransform: 'uppercase' }}>Admin Dashboard</p>
                <div style={{ background: 'rgba(0,217,255,0.1)', padding: '1rem', borderRadius: '8px', marginBottom: '1.5rem', fontSize: '12px' }}>
                  <p style={{ margin: '0.5rem 0', color: '#aaa' }}>👥 Users: <span style={{ color: '#00d9ff', fontWeight: '700' }}>{adminStats.users}</span></p>
                  <p style={{ margin: '0.5rem 0', color: '#aaa' }}>💰 Revenue: <span style={{ color: '#00d9ff', fontWeight: '700' }}>{adminStats.revenue}</span></p>
                  <p style={{ margin: '0.5rem 0', color: '#aaa' }}>📊 Subs: <span style={{ color: '#00d9ff', fontWeight: '700' }}>{adminStats.subs}</span></p>
                </div>
              </>
            )}

            <p style={{ margin: '0 0 1rem', fontSize: '11px', color: '#00d9ff', fontWeight: '700', textTransform: 'uppercase' }}>Navigation</p>
            <button onClick={() => setActiveTab('screener')} style={{ width: '100%', padding: '0.75rem', background: activeTab === 'screener' ? 'rgba(0,217,255,0.15)' : 'transparent', color: activeTab === 'screener' ? '#00d9ff' : '#aaa', border: 'none', textAlign: 'left', cursor: 'pointer', fontSize: '14px', fontWeight: activeTab === 'screener' ? '600' : '400', borderLeft: activeTab === 'screener' ? '3px solid #00d9ff' : '3px solid transparent', transition: 'all 0.2s', marginBottom: '0.5rem' }}>📊 Scanner</button>
            <button onClick={() => setActiveTab('watchlist')} style={{ width: '100%', padding: '0.75rem', background: activeTab === 'watchlist' ? 'rgba(0,217,255,0.15)' : 'transparent', color: activeTab === 'watchlist' ? '#00d9ff' : '#aaa', border: 'none', textAlign: 'left', cursor: 'pointer', fontSize: '14px', fontWeight: activeTab === 'watchlist' ? '600' : '400', borderLeft: activeTab === 'watchlist' ? '3px solid #00d9ff' : '3px solid transparent', transition: 'all 0.2s', marginBottom: '0.5rem' }}>❤️ Watchlist</button>
            <button onClick={() => setActiveTab('alerts')} style={{ width: '100%', padding: '0.75rem', background: activeTab === 'alerts' ? 'rgba(0,217,255,0.15)' : 'transparent', color: activeTab === 'alerts' ? '#00d9ff' : '#aaa', border: 'none', textAlign: 'left', cursor: 'pointer', fontSize: '14px', fontWeight: activeTab === 'alerts' ? '600' : '400', borderLeft: activeTab === 'alerts' ? '3px solid #00d9ff' : '3px solid transparent', transition: 'all 0.2s' }}>🔔 Alerts ({alerts.length})</button>

            <div style={{ position: 'absolute', bottom: '1.5rem', left: '1.5rem', right: '1.5rem' }}>
              <button style={{ width: '100%', padding: '0.75rem', background: '#00d9ff', color: '#0a0a14', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: '700', fontSize: '12px', marginBottom: '0.75rem' }}>Upgrade to Pro</button>
              <button onClick={handleLogout} style={{ width: '100%', padding: '0.75rem', background: 'transparent', color: '#ff6b6b', border: '1px solid rgba(255,107,107,0.3)', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '12px' }}>Sign Out</button>
            </div>
          </div>
        )}

        {/* MAIN CONTENT */}
        <div style={{ flex: 1, padding: mobileView ? '1rem' : '2rem', overflowY: 'auto', maxHeight: '100vh' }}>
          {/* TOP BAR */}
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem', gap: '1rem', flexWrap: 'wrap' }}>
            {!sidebarOpen && <button onClick={() => setSidebarOpen(true)} style={{ background: 'none', border: 'none', color: '#00d9ff', cursor: 'pointer', fontSize: '24px' }}>☰</button>}
            {activeTab === 'screener' && (
              <form onSubmit={handleScan} style={{ display: 'flex', gap: '0.5rem', flex: 1, minWidth: mobileView ? '100%' : '300px' }}>
                <div style={{ position: 'relative', flex: 1 }}>
                  <Search size={16} style={{ position: 'absolute', left: '0.75rem', top: '50%', transform: 'translateY(-50%)', color: '#666' }} />
                  <input type="text" placeholder="AAPL,MSFT,GOOGL..." value={scanInput} onChange={(e) => setScanInput(e.target.value)} style={{ width: '100%', padding: '0.625rem 0.75rem 0.625rem 2.25rem', borderRadius: '6px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '13px' }} />
                </div>
                <button type="submit" disabled={loading} style={{ padding: '0.625rem 1.25rem', background: '#00d9ff', color: '#0a0a14', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '700', fontSize: '12px', opacity: loading ? 0.5 : 1 }}>{loading ? 'Scanning...' : 'Scan'}</button>
              </form>
            )}
          </div>

          {/* SCREENER TAB */}
          {activeTab === 'screener' && (
            <>
              {scanResults.length > 0 && (
                <>
                  <h2 style={{ margin: '1rem 0 2rem', fontSize: mobileView ? '18px' : '24px', fontWeight: '700' }}>Trading Setups ({scanResults.length})</h2>
                  <div style={{ display: 'grid', gridTemplateColumns: mobileView ? '1fr' : 'repeat(auto-fit, minmax(550px, 1fr))', gap: '2rem', marginBottom: '2rem' }}>
                    {scanResults.map((stock, i) => (
                      <div key={i} onClick={() => { setSelectedStock(stock); setChartData(generateChartData()); setLines([]); }} style={{ background: 'rgba(0,217,255,0.05)', border: selectedStock?.ticker === stock.ticker ? '2px solid #00d9ff' : '1px solid rgba(0,217,255,0.2)', borderRadius: '12px', padding: mobileView ? '1rem' : '1.5rem', cursor: 'pointer', transition: 'all 0.3s' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '1rem' }}>
                          <div>
                            <h3 style={{ margin: '0 0 0.25rem', fontSize: mobileView ? '18px' : '22px', fontWeight: '800' }}>{stock.ticker}</h3>
                            <p style={{ margin: 0, color: '#00d9ff', fontSize: '11px', fontWeight: '600' }}>${stock.price}</p>
                          </div>
                          <button onClick={(e) => { e.stopPropagation(); toggleWatchlist(stock.ticker); }} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '20px', color: watchlist.includes(stock.ticker) ? '#ff6b6b' : '#666', transition: 'all 0.2s' }}>♡</button>
                        </div>

                        <p style={{ margin: 0, color: stock.change > 0 ? '#4ade80' : '#ff6b6b', fontWeight: '700', fontSize: '16px', marginBottom: '1rem' }}>
                          {stock.change > 0 ? '▲' : '▼'} {stock.change}% ({stock.percentChange}%)
                        </p>

                        {/* MINI CHART */}
                        <ResponsiveContainer width="100%" height={mobileView ? 100 : 150}>
                          <LineChart data={generateChartData()}>
                            <CartesianGrid strokeDasharray="3 3" stroke="rgba(0,217,255,0.1)" />
                            <XAxis dataKey="time" stroke="#666" style={{ fontSize: '10px' }} />
                            <YAxis stroke="#666" style={{ fontSize: '10px' }} />
                            <Line type="monotone" dataKey="price" stroke="#00d9ff" strokeWidth={2} dot={false} />
                          </LineChart>
                        </ResponsiveContainer>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '0.75rem', marginTop: '1rem', paddingTop: '1rem', borderTop: '1px solid rgba(0,217,255,0.1)' }}>
                          <div>
                            <p style={{ margin: '0 0 0.25rem', color: '#666', fontSize: '9px', fontWeight: '600', textTransform: 'uppercase' }}>RSI</p>
                            <p style={{ margin: 0, color: stock.rsi > 70 ? '#ff6b6b' : stock.rsi < 30 ? '#4ade80' : '#00d9ff', fontSize: '13px', fontWeight: '700' }}>{stock.rsi}</p>
                          </div>
                          <div>
                            <p style={{ margin: '0 0 0.25rem', color: '#666', fontSize: '9px', fontWeight: '600', textTransform: 'uppercase' }}>MACD</p>
                            <p style={{ margin: 0, color: '#00d9ff', fontSize: '13px', fontWeight: '700' }}>{stock.macd}</p>
                          </div>
                          <div>
                            <p style={{ margin: '0 0 0.25rem', color: '#666', fontSize: '9px', fontWeight: '600', textTransform: 'uppercase' }}>VOL</p>
                            <p style={{ margin: 0, color: '#aaa', fontSize: '13px', fontWeight: '700' }}>{(stock.volume / 1000000).toFixed(1)}M</p>
                          </div>
                        </div>

                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem', marginTop: '1rem' }}>
                          {stock.earningsGap && <span style={{ background: 'rgba(74,222,128,0.2)', color: '#4ade80', padding: '0.25rem 0.5rem', borderRadius: '3px', fontSize: '10px', fontWeight: '600' }}>Earnings</span>}
                          {stock.breakout && <span style={{ background: 'rgba(0,217,255,0.2)', color: '#00d9ff', padding: '0.25rem 0.5rem', borderRadius: '3px', fontSize: '10px', fontWeight: '600' }}>Breakout</span>}
                          {stock.oversold && <span style={{ background: 'rgba(139,92,246,0.2)', color: '#c4b5fd', padding: '0.25rem 0.5rem', borderRadius: '3px', fontSize: '10px', fontWeight: '600' }}>Oversold</span>}
                          {stock.volumeSpike && <span style={{ background: 'rgba(255,193,7,0.2)', color: '#ffc107', padding: '0.25rem 0.5rem', borderRadius: '3px', fontSize: '10px', fontWeight: '600' }}>Volume</span>}
                        </div>
                      </div>
                    ))}
                  </div>
                </>
              )}

              {/* DETAILED CHART VIEW */}
              {selectedStock && (
                <div style={{ background: 'rgba(0,217,255,0.05)', border: '1px solid rgba(0,217,255,0.2)', borderRadius: '12px', padding: mobileView ? '1rem' : '2rem', marginBottom: '2rem' }}>
                  <div style={{ display: mobileView ? 'block' : 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '1.5rem', gap: '1rem' }}>
                    <h2 style={{ margin: 0, fontSize: mobileView ? '18px' : '28px', fontWeight: '700' }}>{selectedStock.ticker} - Professional Analysis</h2>
                    <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
                      <button onClick={() => setDrawMode(drawMode === 'trendline' ? null : 'trendline')} style={{ padding: '0.5rem 0.75rem', background: drawMode === 'trendline' ? '#00d9ff' : 'rgba(0,217,255,0.2)', color: drawMode === 'trendline' ? '#0a0a14' : '#00d9ff', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '12px' }}>📈 Trend</button>
                      <button onClick={() => setDrawMode(drawMode === 'support' ? null : 'support')} style={{ padding: '0.5rem 0.75rem', background: drawMode === 'support' ? '#ff6b6b' : 'rgba(255,107,107,0.2)', color: drawMode === 'support' ? 'white' : '#ff6b6b', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '12px' }}>📊 Support</button>
                      <button onClick={clearDrawing} style={{ padding: '0.5rem 0.75rem', background: 'rgba(255,107,107,0.2)', color: '#ff6b6b', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '12px' }}>🗑️ Clear</button>
                      <button onClick={downloadChart} style={{ padding: '0.5rem 0.75rem', background: 'rgba(0,217,255,0.2)', color: '#00d9ff', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '12px' }}>📥 Export</button>
                    </div>
                  </div>

                  {/* LARGE CHART */}
                  <div style={{ position: 'relative', background: 'rgba(10,10,20,0.5)', borderRadius: '8px', overflow: 'hidden', marginBottom: '1.5rem', border: '1px solid rgba(0,217,255,0.1)', height: mobileView ? '300px' : '500px' }}>
                    <ResponsiveContainer width="100%" height="100%">
                      <LineChart data={generateChartData()}>
                        <CartesianGrid strokeDasharray="3 3" stroke="rgba(0,217,255,0.1)" />
                        <XAxis dataKey="time" stroke="#666" style={{ fontSize: '12px' }} />
                        <YAxis stroke="#666" style={{ fontSize: '12px' }} />
                        <Tooltip contentStyle={{ background: 'rgba(10,10,20,0.95)', border: '1px solid rgba(0,217,255,0.2)', borderRadius: '8px', color: 'white' }} />
                        <Line type="monotone" dataKey="price" stroke="#00d9ff" strokeWidth={3} dot={false} />
                        <Line type="monotone" dataKey="sma20" stroke="#ff6b6b" strokeWidth={1} strokeDasharray="5 5" dot={false} />
                        <Line type="monotone" dataKey="sma50" stroke="#4ade80" strokeWidth={1} strokeDasharray="5 5" dot={false} />
                      </LineChart>
                    </ResponsiveContainer>
                    <canvas
                      ref={canvasRef}
                      onMouseDown={handleChartMouseDown}
                      onMouseMove={handleChartMouseMove}
                      onMouseUp={handleChartMouseUp}
                      onMouseLeave={handleChartMouseUp}
                      style={{ position: 'absolute', top: 0, left: 0, cursor: drawMode ? 'crosshair' : 'default', display: 'block' }}
                      width={800}
                      height={400}
                    />
                  </div>

                  {/* METRICS GRID */}
                  <div style={{ display: 'grid', gridTemplateColumns: mobileView ? 'repeat(2, 1fr)' : 'repeat(4, 1fr)', gap: '1rem' }}>
                    {[
                      { label: 'RSI(14)', value: selectedStock.rsi14, color: '#00d9ff' },
                      { label: 'MACD', value: selectedStock.macd, color: '#ff6b6b' },
                      { label: 'P/E', value: selectedStock.pe_ratio, color: '#4ade80' },
                      { label: 'Earnings', value: selectedStock.earnings_date, color: '#ffc107' },
                      { label: 'SMA20', value: selectedStock.sma20, color: '#00d9ff' },
                      { label: 'SMA200', value: selectedStock.sma200, color: '#ff6b6b' },
                      { label: 'ATR', value: selectedStock.atr, color: '#4ade80' },
                      { label: 'Analysts', value: selectedStock.analyst, color: '#ffc107' },
                    ].map((m, i) => (
                      <div key={i} style={{ background: 'rgba(10,10,20,0.5)', padding: '1rem', borderRadius: '8px', border: '1px solid rgba(0,217,255,0.1)' }}>
                        <p style={{ margin: '0 0 0.5rem', color: '#666', fontSize: '10px', fontWeight: '600', textTransform: 'uppercase' }}>{m.label}</p>
                        <p style={{ margin: 0, color: m.color, fontSize: '16px', fontWeight: '700' }}>{m.value}</p>
                      </div>
                    ))}
                  </div>

                  <div style={{ marginTop: '1.5rem', padding: '1rem', background: 'rgba(0,217,255,0.1)', borderRadius: '8px', fontSize: '12px', color: '#aaa' }}>
                    💡 {drawMode ? `Drawing ${drawMode}... Click and drag on chart` : 'Click "Trend" or "Support" button to annotate the chart'}
                  </div>
                </div>
              )}

              {scanResults.length === 0 && (
                <div style={{ textAlign: 'center', padding: '4rem 2rem', color: '#666' }}>
                  <TrendingUp size={48} style={{ margin: '0 auto 1rem', opacity: 0.3 }} />
                  <p style={{ fontSize: mobileView ? '14px' : '18px', margin: 0 }}>Enter stock tickers to scan</p>
                  <p style={{ fontSize: '12px', color: '#444', margin: '0.5rem 0 0' }}>Example: AAPL,MSFT,GOOGL,TSLA,AMZN</p>
                </div>
              )}
            </>
          )}

          {/* WATCHLIST TAB */}
          {activeTab === 'watchlist' && (
            <>
              {watchlist.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '4rem 2rem', color: '#666' }}>
                  <Heart size={48} style={{ margin: '0 auto 1rem', opacity: 0.3 }} />
                  <p style={{ fontSize: '16px', margin: 0 }}>No stocks in watchlist</p>
                  <p style={{ fontSize: '12px', color: '#444', margin: '0.5rem 0 0' }}>Add stocks by clicking the ♡ icon</p>
                </div>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: mobileView ? '1fr' : 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1.5rem' }}>
                  {scanResults.filter(s => watchlist.includes(s.ticker)).map((stock, i) => (
                    <div key={i} style={{ background: 'rgba(0,217,255,0.05)', border: '1px solid rgba(0,217,255,0.2)', borderRadius: '12px', padding: '1.5rem' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '1rem' }}>
                        <h3 style={{ margin: 0, fontSize: '18px', fontWeight: '800' }}>{stock.ticker}</h3>
                        <button onClick={() => toggleWatchlist(stock.ticker)} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '18px', color: '#ff6b6b' }}>♡</button>
                      </div>
                      <p style={{ margin: '0.5rem 0', color: stock.change > 0 ? '#4ade80' : '#ff6b6b', fontWeight: 'bold', fontSize: '14px' }}>{stock.change > 0 ? '▲' : '▼'} {stock.change}%</p>
                      <p style={{ margin: '0.5rem 0', color: '#aaa', fontSize: '12px' }}>Price: ${stock.price}</p>
                      <p style={{ margin: '0.5rem 0 1rem', color: '#aaa', fontSize: '12px' }}>Earnings: {stock.earnings_date}</p>
                      <button onClick={() => addAlert(stock.ticker, '')} style={{ width: '100%', padding: '0.75rem', background: 'rgba(0,217,255,0.2)', color: '#00d9ff', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '12px' }}>Set Alert</button>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}

          {/* ALERTS TAB */}
          {activeTab === 'alerts' && (
            <>
              <div style={{ background: 'rgba(0,217,255,0.05)', border: '1px solid rgba(0,217,255,0.2)', borderRadius: '12px', padding: '1.5rem', marginBottom: '2rem' }}>
                <h3 style={{ margin: '0 0 1rem', fontSize: '16px', fontWeight: '700' }}>Create New Alert</h3>
                <form onSubmit={(e) => { e.preventDefault(); addAlert('', alertPrice); }} style={{ display: 'flex', gap: '0.75rem', flexWrap: 'wrap' }}>
                  <input type="text" placeholder="Ticker (e.g. AAPL)" style={{ flex: 1, minWidth: '120px', padding: '0.625rem', borderRadius: '6px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '12px' }} />
                  <input type="number" placeholder="Price" value={alertPrice} onChange={(e) => setAlertPrice(e.target.value)} style={{ flex: 1, minWidth: '100px', padding: '0.625rem', borderRadius: '6px', border: '1px solid rgba(0,217,255,0.2)', background: 'rgba(10,10,20,0.5)', color: 'white', fontSize: '12px' }} />
                  <button type="submit" style={{ padding: '0.625rem 1rem', background: '#00d9ff', color: '#0a0a14', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '700', fontSize: '12px' }}>Add Alert</button>
                </form>
              </div>

              {alerts.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '4rem 2rem', color: '#666' }}>
                  <AlertCircle size={48} style={{ margin: '0 auto 1rem', opacity: 0.3 }} />
                  <p style={{ fontSize: '16px', margin: 0 }}>No alerts yet</p>
                </div>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: mobileView ? '1fr' : 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1rem' }}>
                  {alerts.map((alert, i) => (
                    <div key={i} style={{ background: 'rgba(0,217,255,0.05)', border: '1px solid rgba(0,217,255,0.2)', borderRadius: '12px', padding: '1.5rem' }}>
                      <h4 style={{ margin: 0, fontSize: '16px', fontWeight: '700' }}>{alert.ticker}</h4>
                      <p style={{ margin: '0.75rem 0 0', color: '#00d9ff', fontWeight: '700' }}>Alert at: ${alert.price}</p>
                      <button onClick={() => setAlerts(alerts.filter(a => a.id !== alert.id))} style={{ width: '100%', marginTop: '1rem', padding: '0.5rem', background: '#ff6b6b', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', fontSize: '11px' }}>Delete</button>
                    </div>
                  ))}
                </div>
              )}
            </>
          )}
        </div>
      </div>
    );
  }

  return null;
};

export default App;
